export type WorkplaceBenefit = {
  title: string;
  description: string;
  category: "Health & Medical" | "Financial & Stock" | "Workplace Flex" | "Learning & Education" | "Career Growth" | "Perks";
};

export type GlassdoorReview = {
  id: string;
  role: string;
  rating: number;
  pros: string;
  cons: string;
  date: string;
  employmentStatus: string;
};

export type CompanyFAQ = {
  question: string;
  answer: string;
};

export type SocialLinks = {
  linkedin?: string;
  twitter?: string;
  facebook?: string;
  instagram?: string;
  youtube?: string;
  glassdoor?: string;
  crunchbase?: string;
  wikipedia?: string;
};

